var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"……그런 일이 있었군요.","JPN":"……そんなことがあったんですね。","ENG":"...So, that's what happened.","TWN":"……原來是這樣。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"병문안이 늦어져서 미안하네. 변명이라고 하기엔 구차하네만.","JPN":"お見舞いが遅くなって悪いかったね。言い訳にしてはお粗末だったが。","ENG":"I'm sorry for taking this long to visit. I have no excuse for it.","TWN":"抱歉，這麼晚才來看你，這個解釋很站不住腳吧？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"너무 쉽게 납득해 줘서 놀랐다네.","JPN":"あまりにもすんなり納得してくれて驚いたよ。","ENG":"But I am surprised you understood it so easily.","TWN":"沒想到你這麼容易就接受。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"모시는 주인님의 성품을 알아보는 것도 메이드가 갖춰야 할 덕목이죠.","JPN":"お仕えするご主人様の人となりを見抜くことも、メイドが備えるべき徳目ですので。","ENG":"It is a maid's virtue to be adept of know her master's character.","TWN":"明白主人的品格也是女僕應該具備的特質。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"이렇게 몸소 와 주셔서 영광입니다.","JPN":"こうやって直接お越しいただくなんて、恐縮です。","ENG":"I am honored that you came to visit me.","TWN":"主人親自造訪，是我的榮幸。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 관리국의 개입은 다소 우려스럽군요.","JPN":"ですが、管理局の介入は少々心配ですね。","ENG":"But the intervention of the Administration is somewhat concerning.","TWN":"不過管理局的介入令人有點擔心呢。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"절묘한 시기를 노렸다는 인상을 지우기 어렵습니다.","JPN":"絶妙な時期を狙っていたという印象を拭いきれません。","ENG":"I can't shake the feeling that they were deliberately waiting for the right moment.","TWN":"畢竟很難消除他們虎視眈眈的印象。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……동감일세. 그건 차차 알아나가야지.","JPN":"……同感だ。それはこれから調べないとな。","ENG":"...I couldn't agree with you more. But we will find out soon enough.","TWN":"……我同意，必須慢慢釐清。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"당분간 내 걱정은 말고 자네 몸조리에 신경 쓰게나.","JPN":"しばらくは私の心配はせず、自分の身体を労わりたまえ。","ENG":"For the time being, don't worry about me and take care of yourself.","TWN":"這段時間你就別擔心我，好好保重身體。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"모네 양의 고향으로 요양을 간다고 했던가?","JPN":"モネ君の故郷まで療養に行くと言ったかな？","ENG":"I understand you're going to Mone's hometown to rest, is that right?","TWN":"我聽說你要去莫妮的家鄉修養嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"네. 모네 양 어머님께서도 흔쾌히 허락해 주셔서, 퇴원하는 대로 신세를 질 듯합니다.","JPN":"はい。モネさんのお母様も快諾してくださいましたので、退院でき次第お世話になることになりそうです。","ENG":"Yes. Mone's mother happily obliged, so I will be staying there once I get discharged from here.","TWN":"是的，莫妮的媽媽也很爽快地答應，等我出院後就會去他們家打擾。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그래도 제가 필요하실 때는, 언제든 불러 주시길.","JPN":"でも必要があれば、いつでもお呼びください。","ENG":"However, please call me when you need my help.","TWN":"不過主人有需要我時，請隨時找我。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런 말 말게. 당장 자네에게 진 빚을 갚기도 빠듯해.","JPN":"そんなこと言わないでくれ。君への恩を返すのも精一杯さ。","ENG":"Don't say that. It is hard enough to repay you as it is now.","TWN":"別這麼說，我之前欠你的人情債都還沒還清呢。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……그럼 가 보겠네. 편히 쉬게나. 베로니카 양.","JPN":"……それでは、これで失礼する。ゆっくり休みたまえ。ベロニカ君。","ENG":"...Then, I better get going. Rest well, Veronica.","TWN":"……那我先走一步，你好好休息，貝洛妮卡。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"네. 주인님.","JPN":"はい。ご主人様。","ENG":"Yes, Master.","TWN":"好的，主人。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"모쪼록 주인님의 앞날에 행운이 기다리고 있기를 기원하겠습니다.","JPN":"どうか、ご主人様の未来に幸運がありますことを。","ENG":"I wish you the best of luck in the future, Master.","TWN":"希望主人之後一切都順利。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_02","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};